sed -i '106a\
\
	// IsAvailableFilter is a function that can be used to filter the availability\
	// of a command based on the execution context. If it returns false, the command\
	// will be considered unavailable.\
	IsAvailableFilter func(context.Context) bool' /workspace/repo/command.go

cat > /tmp/update_isavailable.py << 'EOF'
import re

with open('/workspace/repo/command.go', 'r') as f:
    content = f.read()

# Find and replace the IsAvailableCommand function
old_func = '''// IsAvailableCommand determines if a command is available as a non-help command
// (this includes all non deprecated/hidden commands).
func (c *Command) IsAvailableCommand() bool {
	if len(c.Deprecated) != 0 || c.Hidden {
		return false
	}

	if c.HasParent() && c.Parent().helpCommand == c {
		return false
	}

	if c.Runnable() || c.HasAvailableSubCommands() {
		return true
	}

	return false
}'''

new_func = '''// IsAvailableCommand determines if a command is available as a non-help command
// (this includes all non deprecated/hidden commands).
func (c *Command) IsAvailableCommand() bool {
	if len(c.Deprecated) != 0 || c.Hidden {
		return false
	}

	if c.HasParent() && c.Parent().helpCommand == c {
		return false
	}

	if c.IsAvailableFilter != nil && !c.IsAvailableFilter(c.Context()) {
		return false
	}

	if c.Runnable() || c.HasAvailableSubCommands() {
		return true
	}

	return false
}'''

content = content.replace(old_func, new_func)

with open('/workspace/repo/command.go', 'w') as f:
    f.write(content)

print("Updated IsAvailableCommand function")
EOF
python3 /tmp/update_isavailable.py

