cat > /tmp/test_cobra_features.go << 'EOF'
package main

import (
	"context"
	"fmt"
	"os"

	"github.com/spf13/cobra"
)

func main() {
	// Test Feature 1: Context Propagation to Subcommands in Help Functions
	fmt.Println("=== Testing Feature 1: Context Propagation ===")
	testContextPropagation()

	// Test Feature 2: Dynamic Command Availability Filtering
	fmt.Println("\n=== Testing Feature 2: Dynamic Command Availability Filtering ===")
	testDynamicAvailability()

	fmt.Println("\n=== All tests completed ===")
}

func testContextPropagation() {
	rootCmd := &cobra.Command{
		Use:   "root",
		Short: "Root command for testing",
		Run: func(cmd *cobra.Command, args []string) {
			fmt.Println("Root command executed")
		},
	}

	subCmd := &cobra.Command{
		Use:   "sub",
		Short: "Sub command",
		Run: func(cmd *cobra.Command, args []string) {
			ctx := cmd.Context()
			if ctx == nil {
				fmt.Println("ERROR: Context is nil!")
			} else {
				fmt.Println("SUCCESS: Context is available in subcommand")
			}
		},
	}

	rootCmd.AddCommand(subCmd)

	// Set context on root and execute
	ctx := context.WithValue(context.Background(), "testKey", "testValue")
	rootCmd.SetContext(ctx)

	// Simulate help <subcommand> scenario
	// Find the subcommand and call help on it with propagated context
	_, foundErr := rootCmd.Find([]string{"help", "sub"})
	if foundErr == nil {
		// Manually test context propagation
		sub, _, _ := rootCmd.Find([]string{"sub"})
		fmt.Printf("Before context propagation - sub.Context() is nil: %v\n", sub.Context() == nil)

		// Simulate what help command does
		if sub.Context() == nil {
			sub.SetContext(rootCmd.Context())
		}
		fmt.Printf("After context propagation - sub.Context() is nil: %v\n", sub.Context() == nil)
	}
}

func testDynamicAvailability() {
	// Create a root command with a filter
	rootCmd := &cobra.Command{
		Use:   "root",
		Short: "Root command for testing dynamic availability",
	}

	// Command with available filter that checks a specific value in context
	cmd1 := &cobra.Command{
		Use: "cmd1",
		Run: func(cmd *cobra.Command, args []string) {
			fmt.Println("cmd1 executed")
		},
		IsAvailableFilter: func(ctx context.Context) bool {
			val := ctx.Value("enableCmd1")
			if val == true {
				fmt.Println("cmd1: Filter passed - enabled")
				return true
			}
			fmt.Println("cmd1: Filter denied - disabled")
			return false
		},
	}

	cmd2 := &cobra.Command{
		Use: "cmd2",
		Run: func(cmd *cobra.Command, args []string) {
			fmt.Println("cmd2 executed")
		},
		IsAvailableFilter: func(ctx context.Context) bool {
			val := ctx.Value("enableCmd2")
			if val == true {
				fmt.Println("cmd2: Filter passed - enabled")
				return true
			}
			fmt.Println("cmd2: Filter denied - disabled")
			return false
		},
	}

	cmd3 := &cobra.Command{
		Use: "cmd3",
		Run: func(cmd *cobra.Command, args []string) {
			fmt.Println("cmd3 executed (no filter)")
		},
		// No IsAvailableFilter - should always be available
	}

	rootCmd.AddCommand(cmd1, cmd2, cmd3)

	// Test with only cmd1 enabled
	fmt.Println("\nTesting with only cmd1 enabled:")
	ctx1 := context.WithValue(context.Background(), "enableCmd1", true)
	rootCmd1 := rootCmd
	rootCmd1.SetContext(ctx1)
	fmt.Printf("cmd1 IsAvailableCommand: %v\n", cmd1.IsAvailableCommand())
	fmt.Printf("cmd2 IsAvailableCommand: %v\n", cmd2.IsAvailableCommand())
	fmt.Printf("cmd3 IsAvailableCommand: %v\n", cmd3.IsAvailableCommand())

	// Test with both enabled
	fmt.Println("\nTesting with cmd1 and cmd2 enabled:")
	ctx2 := context.WithValue(context.Background(), "enableCmd1", true)
	ctx2 = context.WithValue(ctx2, "enableCmd2", true)
	cmd1.SetContext(ctx2)
	cmd2.SetContext(ctx2)
	cmd3.SetContext(ctx2)
	fmt.Printf("cmd1 IsAvailableCommand: %v\n", cmd1.IsAvailableCommand())
	fmt.Printf("cmd2 IsAvailableCommand: %v\n", cmd2.IsAvailableCommand())
	fmt.Printf("cmd3 IsAvailableCommand: %v\n", cmd3.IsAvailableCommand())
}
